import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';

// Pages
import Login from './pages/Auth/Login';
import Register from './pages/Auth/Register';
import Dashboard from './pages/Dashboard';
import BookList from './pages/Books/BookList';

// Composant d'accueil
const Home = () => {
  const [backendStatus, setBackendStatus] = useState('Vérification...');
  const [books, setBooks] = useState([]);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    // Test de connexion au backend
    console.log('Tentative de connexion au backend...');

    fetch('http://localhost:5000/health', {
      method: 'GET',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json'
      },
      mode: 'cors'
    })
    .then(res => {
      console.log('Réponse reçue:', res.status);
      if (!res.ok) {
        throw new Error(`HTTP error! status: ${res.status}`);
      }
      return res.json();
    })
    .then(data => {
      console.log('Données reçues:', data);
      setBackendStatus('✅ Connecté au backend');
      setError('');

      // Maintenant charger les livres
      return fetch('http://localhost:5000/api/books', {
        method: 'GET',
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        },
        mode: 'cors'
      });
    })
    .then(res => res.json())
    .then(data => {
      console.log('Livres reçus:', data);
      setBooks(data.data || []);
    })
    .catch(err => {
      console.error('Erreur détaillée:', err);
      setBackendStatus('❌ Non connecté au backend');
      setError(err.message);
    });
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/');
  };

  // Vérifier si l'utilisateur est connecté
  const token = localStorage.getItem('token');
  const userStr = localStorage.getItem('user');
  const user = userStr ? JSON.parse(userStr) : null;

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Navbar */}
      <nav className="bg-white shadow-lg">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <Link to="/" className="text-xl font-bold text-blue-600">📚 LibraryManager</Link>
            </div>
            <div className="flex items-center space-x-4">
              <Link to="/" className="text-gray-700 hover:text-blue-600 px-3 py-2">Accueil</Link>
              <Link to="/books" className="text-gray-700 hover:text-blue-600 px-3 py-2">Livres</Link>

              {user ? (
                <>
                  <span className="text-gray-700">Bonjour, {user.firstName}</span>
                  <Link to="/dashboard" className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">
                    Dashboard
                  </Link>
                  <button
                    onClick={handleLogout}
                    className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700"
                  >
                    Déconnexion
                  </button>
                </>
              ) : (
                <>
                  <Link to="/login" className="text-gray-700 hover:text-blue-600 px-3 py-2">Connexion</Link>
                  <Link to="/register" className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">
                    Inscription
                  </Link>
                </>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* Main content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Status card */}
        <div className="bg-white rounded-lg shadow-md p-6 mb-8">
          <h2 className="text-xl font-semibold mb-4">État du système</h2>
          <div className="space-y-2">
            <p className="text-gray-700">
              <span className="font-medium">Backend:</span> {backendStatus}
            </p>
            {error && (
              <p className="text-red-600 text-sm">
                Erreur: {error}
              </p>
            )}
            <p className="text-gray-700">
              <span className="font-medium">Frontend:</span> ✅ http://localhost:3000
            </p>
            <p className="text-gray-700">
              <span className="font-medium">API URL:</span> http://localhost:5000/api
            </p>
          </div>
        </div>

        {/* Welcome section */}
        <div className="bg-gradient-to-r from-blue-500 to-blue-700 text-white rounded-lg shadow-lg p-12 mb-8 text-center">
          <h1 className="text-4xl font-bold mb-4">
            Bienvenue à la Bibliothèque
          </h1>
          <p className="text-xl mb-8">
            Gérez vos emprunts, découvrez des livres et interagissez avec la communauté
          </p>
          <div className="space-x-4">
            <Link 
              to="/books" 
              className="bg-white text-blue-600 px-8 py-3 rounded-lg font-semibold hover:bg-gray-100 inline-block"
            >
              Parcourir les livres
            </Link>
            {!user && (
              <Link 
                to="/register" 
                className="bg-blue-700 text-white px-8 py-3 rounded-lg font-semibold hover:bg-blue-800 inline-block"
              >
                S'inscrire
              </Link>
            )}
          </div>
        </div>

        {/* Books Grid - Afficher les livres si disponibles */}
        {books.length > 0 && (
          <div className="mb-8">
            <h2 className="text-2xl font-bold mb-4">Livres populaires</h2>
            <div className="grid md:grid-cols-4 gap-4">
              {books.slice(0, 4).map(book => (
                <Link to={`/books/${book._id}`} key={book._id} className="bg-white rounded-lg shadow p-4 hover:shadow-lg transition">
                  <div className="text-4xl mb-2 text-center">📖</div>
                  <h3 className="font-bold text-center">{book.title}</h3>
                  <p className="text-sm text-gray-600 text-center">{book.author}</p>
                  <p className="text-xs text-gray-500 text-center mt-2">
                    {book.availableCopies}/{book.totalCopies} disponibles
                  </p>
                </Link>
              ))}
            </div>
          </div>
        )}

        {/* Features grid */}
        <div className="grid md:grid-cols-3 gap-6">
          <div className="bg-white rounded-lg shadow-md p-6 text-center">
            <div className="text-4xl mb-4">📖</div>
            <h3 className="text-lg font-semibold mb-2">Catalogue complet</h3>
            <p className="text-gray-600">Parcourez des milliers de livres avec recherche avancée</p>
          </div>

          <div className="bg-white rounded-lg shadow-md p-6 text-center">
            <div className="text-4xl mb-4">🔄</div>
            <h3 className="text-lg font-semibold mb-2">Emprunts faciles</h3>
            <p className="text-gray-600">Empruntez, prolongez et retournez en quelques clics</p>
          </div>

          <div className="bg-white rounded-lg shadow-md p-6 text-center">
            <div className="text-4xl mb-4">⭐</div>
            <h3 className="text-lg font-semibold mb-2">Avis et notes</h3>
            <p className="text-gray-600">Partagez votre avis et découvrez les recommandations</p>
          </div>
        </div>
      </main>
    </div>
  );
};

// Composant App principal avec routage
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/books" element={<BookList />} />
        <Route path="/books/:id" element={<BookDetail />} />
        <Route path="/dashboard" element={<Dashboard />} />
      </Routes>
    </Router>
  );
}

export default App;
